	.TITLE	PRINT	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM8		; df diverses	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	BIOS	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df drivers	.REF	DBOX		; df botes de dialogue	.REF	SABLIER		; df sabliersNOREV	=	1NOVERS	=	4	.REV	NOREV,NOVERS	.CODE	600,11,B'111,20,2000,20,2000,2,'*,0,0; Constantes; ----------LBUNAM	=	50		; lg buffer pour nomLBUCOM	=	100		; lg buffer pour commandeLBUPRI	=	256		; lg buffer d'impressionLOMBRE	=	6		; dimension pour ombreLDETECTE=	10		; imprcision accepte pour la dtectionFACORX	=	10		; facteur correctif en X (unit = 0.10583mm)FACORY	=	8		; facteur correctif en Y (unit = 0.08819mm)LGMINX	=	30		; dimension minimale en XLGMINY	=	30		; dimension minimale en YCASHTP	=	0		; case pour hauteur de la pageCASLGP	=	1		; case pour largeur de la pageCASMGG	=	2		; case pour la marge de gaucheCASMGD	=	3		; case pour la marge de droiteCASMGS	=	4		; case pour la marge suprieureCASMGI	=	5		; case pour la marge infrieureCASITL	=	6		; case pour l'interligneCASITC	=	7		; case pour l'intercaractreCASNBL	=	8		; case pour le nombre de lignesCASNBC	=	9		; case pour le nombre de caractresCASDEF	=	CASMGG		; case par dfaut (marge de gauche)MAXSEL	=	10		; nb de cases pour les infosEDEOP	=	6		; pseudo-fin de page;EOP	=	12		; fin de page; Dtection de la souris; ----------------------BOPSUP	=	0		; souris sur la ligne suprieureBOPINF	=	1		; souris sur la ligne infrieureBOPGAU	=	2		; souris sur la ligne gaucheBOPDRO	=	3		; souris sur la ligne droite; Variables; ---------	.LOC	0OFLAGS:	.BLKB	1		; flags divers BCOMM	=  0			;  excution d'une commande BDEBUG	=  1			;  provisoire BVERT	=  2			;  commande "verticale" BABORT	=  7			;  signal la fin au filsOMACHINE:.BLKB	1		; numro de la machine	.EVENOCHDBOX:.BLKB	2		; canal module DBOXOCHSABL:.BLKB	2		; canal module SABLIEROSABLIER:.BLKB	4		; canal d'un sablierOPTNAM:	.BLKB	4		; ^nom dans ligne de commandeOBUNAM:	.BLKB	LBUNAM		; buffer pour nom de fichierOBUCOM:	.BLKB	LBUCOM		; buffer pour une commandeOBUSTP:	.BLKB	LGPRI0		; buffer status imprimanteOBUSTD:	.BLKB	LGDIS3		; buffer status fentreOCHKEY:	.BLKB	2		; canal du clavierOBUKEY:	.BLKB	2		; buffer pour commande clavierOPRNBC:	.BLKB	2		; nombre de copiesOPRBPA:	.BLKB	2		; premire pageOPREPA:	.BLKB	2		; dernire pageOPRCPA:	.BLKB	2		; compteur de pagesONOWDT:	.BLKB	2		; no swdo pour texteONOWDG:	.BLKB	2		; no swdo pour graphiqueONOSEL:	.BLKB	2		; no case slectionneOPOINF:	.BLKB	4*MAXSEL	; positions des infosOWDOG:OWDOGY:	.BLKB	2		; origine Y swdo graphiqueOWDOGX:	.BLKB	2		; origine X swdo graphiqueOFACT:	.BLKB	2		; facteur de rductionOOEXT:OOEXTY:	.BLKB	2		; origine Y rectangle extrieurOOEXTX:	.BLKB	2		; origine X rectangle extrieur OLEXT:OLEXTY:	.BLKB	2		; hauteur Y rectangle extrieurOLEXTX:	.BLKB	2		; largeur X rectangle extrieur OOINT:OOINTY:	.BLKB	2		; origine Y rectangle intrieurOOINTX:	.BLKB	2		; origine X rectangle intrieur OLINT:OLINTY:	.BLKB	2		; hauteur Y rectangle intrieurOLINTX:	.BLKB	2		; largeur X rectangle intrieur OOOINT:OOOINTY:.BLKB	2		; ancienne origine Y rectangle intrieurOOOINTX:.BLKB	2		; ancienne origine X rectangle intrieur OOLINT:OOLINTY:.BLKB	2		; ancienne hauteur Y rectangle intrieurOOLINTX:.BLKB	2		; ancienne largeur X rectangle intrieur OMOUOR:	.BLKB	4		; origine de la sourisOINTOR:	.BLKB	4		; origine du coin sup/gaucheOCHIN:	.BLKB	2		; canal en lectureOCHOUT:	.BLKB	2		; canal en sortieOBUPRI:	.BLKB	LBUPRI		; buffer d'impressinLGVAR:; Programme; ---------	.LOC	0START:	.W	LIB,?OPELIB	; ouvre la librairie	LOAD.W	D3,#2		; D3 <-- souris par le clavier	.W	LIB,?MOUSE	; utilise la souris	LOAD.L	A4,#R16"LIBLIST	.W	LIB,?USELIB	; signal les appels utiliss	JUMP,NE	FATERR	LOAD.L	D4,#LGVAR	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE	FATERR	LOAD.L	A6,A4		; A6 <-- ^variables10$:	CLR.B	(A4+)		; met toutes les variables  zro	DEC.W	D4	JUMP,NE	10$	.W	LIB,?GCHKEY	LOAD.W	(A6)+OCHKEY,D6	; mm. canal du clavier	LOAD.B	D3,#'C	.W	LIB,?IFSWITCH	; PRINT/C ?	JUMP,NE	20$		; non => 20$	TSET.B	(A6)+OFLAGS:#BCOMM20$:	LOAD.B	D3,#'X	.W	LIB,?IFSWITCH	; PRINT/X ?	JUMP,NE	25$		; non => 25$	TSET.B	(A6)+OFLAGS:#BDEBUG25$:	CLR.L	(A6)+OPTNAM	.W	LIB,?SKPNAM	; A3 <-- ^nom dans ligne de commande	JUMP,NE	30$	LOAD.L	(A6)+OPTNAM,A330$:	.W	BIOS,?GETMACHINE	SWAP.W	D4	SR.W	D4,#8		; D4 <-- numro de la machine	LOAD.B	(A6)+OMACHINE,D4	LOAD.L	A3,#R16"NAMDBOX	LOAD.W	D3,#DBOX_OPEN	.W	LIB_OPEN	; ouvre le module DBOX	JUMP,NE	FATERR	LOAD.W	(A6)+OCHDBOX,D1	LOAD.L	A3,#R16"NAMSABL	LOAD.W	D3,#SABLIER_OPEN	.W	LIB_OPEN	; ouvre le module SABLIER	JUMP,NE	FATERR	LOAD.W	(A6)+OCHSABL,D1	CALL	INIDIS		; cre les sous-fentres	JUMP,NE	ERRORLOOP:	LOAD.L	A3,#R16"TXMENU	.W	LIB,?AFMENU	CALL	AFREV		; affiche PRINT rev x.y	TEST.B	(A6)+OFLAGS:#BCOMM	JUMP,BS	DOCOMM	TEST.B	(A6)+OFLAGS:#BDEBUG	JUMP,BS	DOCOMMDOPRINT:	CALL	GETFILE		; attend un nom de fichier ...	JUMP,NS	ERROR	JUMP,NE	RETOUR	CALL	DBOXPRINT	; affiche DBOX et attend ...	JUMP,NS	ERROR	JUMP,NE	RETOUR20$:	TEST.W	(A6)+OPRNBC	; encore une copie ?	JUMP,EQ	40$		; non => 40$	DEC.W	(A6)+OPRNBC	; oui =>	CALL	EXPRINT		; imprime ...	JUMP,NE	ERROR	JUMP	20$40$:	.W	LIB,?AFTIM	.B	NOCURS		; plus de curseur	.B	CR	.ASCIZ	"Impression termine correctement"	.EVEN	JUMP	DONEDOCOMM:	CALL	EDICOMM		; dite le format d'une page ...	JUMP,NE	ERROR	JUMP	RETOURDONE:	TEST.L	(A6)+OPTNAM	; qq chose dans ligne de commande ?	JUMP,EQ	LOOP		; non => LOOP				; oui =>	LOAD.W	D3,#BIPDONE	.W	LIB,?BEEP	; joli bruit	LOAD.W	D4,#50*2	; D4 <-- 2 secondes	.W	NTREL,?DELMS	; attend ...	JUMP	RETOURERROR:	PUSH.W	D7	LOAD.W	D3,#BIPERR	.W	LIB,?BEEP	; fait un vilain bruit	POP.W	D7	.W	DBOX_ERROR	; affiche l'erreur et attend ...;	JUMP	RETOURRETOUR:	LOAD.W	D1,(A6)+OCHDBOX	.W	LIB_CLOSE	; ferme le module DBOX;	JUMP	FATERRFATERR:	CLR.W	D5	.W	LIB,?USEWDO	; utilise la swdo principale	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	; efface toute la fentre	.W	LIB,?CLOLIB	; ferme la librairie	.W	FOS,?STOP	; avorte le processus ...; Routines; --------;--------\; AFREV   >;========/; Affiche PRINT rev ...; in	-; out	-; mod	D7.WAFREV:	PUSHM.L	D2,D3,D4	.W	LIB,?AFTIM	.B	EOP		; efface tout	.B	NOCURS		; plus de curseur	.B	CR		; une ligne vide	.ASCIZ	/PRINT rev /	.EVEN	CLR.L	D4	LOAD.B	D4,#NOREV	LOAD.B	D3,#3	LOAD.B	D2,#2^BAFDCM	.W	LIB,?AFDEC	; affiche no rvision	LOAD.B	D3,#'.	.W	LIB,?AFCAR	LOAD.B	D4,#NOVERS	LOAD.B	D3,#3	.W	LIB,?AFDEC	; affiche no version	.W	LIB,?AFCR	.W	LIB,?AFCR	.W	LIB,?AFCR	POPM.L	D2,D3,D4	RET;--------\; GETFILE >;========/; Attend un nom de fichier, ou prend celui donn dans la ligne; de commande.; in	-; out	A3.L	^nom;	D7.W	erreur; mod	D7.W, A3.LGETFILE:	PUSHM.L	D3,D4,A4,A5	TEST.L	(A6)+OPTNAM	; nom dans ligne de commande ?	JUMP,EQ	40$		; non => 40$				; oui =>	.W	LIB,?AFTIM	.ASCIZ	"Impression de "	.EVEN	.W	LIB,?GETCURS	LOAD.L	D4,D3		; D4 <-- position du curseur	LOAD.L	A4,(A6)+OPTNAM	; A4 <-- ^nom dans commande	LOAD.L	A3,#(A6)+OBUNAM	; A3 <-- ^buffer pour nom10$:	LOAD.B	D3,(A4+)	JUMP,EQ	15$	COMP.B	D3,#CR	JUMP,EQ	15$	COMP.B	D3,#SPACE	JUMP,EQ	15$	LOAD.B	(A3+),D3	; buffer <-- nom	JUMP	10$15$:	CLR.B	(A3)		; buffer <-- <terminateur>	LOAD.L	A3,#(A6)+OBUNAM	JUMP	70$40$:	LOAD.L	A3,#R16"TXMEN0	.W	LIB,?AFMENU	; mj les soft-keys	.W	LIB,?AFTIM	.ASCIZ	"Nom du fichier  imprimer : "	.EVEN	.W	LIB,?GETCURS	LOAD.L	D4,D3		; D4 <-- position du curseur	LOAD.L	A3,#(A6)+OBUNAM	CLR.B	(A3)	LOAD.L	A4,A3	LOAD.L	A5,#R16"TKMEN050$:	LOAD.W	D3,#LBUNAM	.W	LIB,?GETFILE	; attend un nom de fichier ...	JUMP,NE	90$	LOAD.W	D7,#1		; D7 <-- touche (END)	COMP.B	D3,#END	JUMP,EQ	90$	COMP.B	D3,#F0	JUMP,EQ	90$	COMP.B	D3,#F0+SHIFT	JUMP,EQ	90$	COMP.B	D3,#CR		; (RETURN) ?	JUMP,EQ	70$		; oui => 70$	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; tout p'tit bruit	JUMP	50$70$:	LOAD.L	A4,#R16"EXTDEF	; A4 <-- ^extension par dfaut	CLR.W	D3		; D3 <-- laisse si dj une	.W	LIB,?ADDEXT	; ajoute l'extension	JUMP,NE	90$	LOAD.L	D3,D4	.W	LIB,?SETCURS	; remet curseur dbut du nom	.W	LIB,?AFFILE	; affiche le nom rel	.W	LIB,?AFCR	; passe  la ligne	CLR.W	D7		; D7 <-- ok90$:	PUSHM.L	D7,A3	LOAD.L	A3,#R16"TXMENU	.W	LIB,?AFMENU	; remet soft-keys standards	POPM.L	D7,A3	POPM.L	D3,D4,A4,A5	TEST.W	D7		; retour EQ/NE	RET;--------\; EXPRINT >;========/; Imprime un fichier quelconque.; in	A3.L	^nom du fichier  imprimer; out	D7.W	erreur; mod	D7.WEXPRINT:	PUSHM.L	D3,D4,D5,D6,A3,A4	.W	LIB,?AFTIM	.B	NOCURS,EOP,CR,CR,CR	.ASCIZ	"  Impression de "	.EVEN	.W	LIB,?AFFILE	; affiche le nom du fichier	.W	LIB,?AFCR	; passe  la ligne	LOAD.W	D3,#2^BOPRD	; D3 <-- ouverture en lecture	.W	FOS,?OPEN	; ouvre fichier  imprimer	JUMP,NE	95$	LOAD.W	(A6)+OCHIN,D6	LOAD.L	D4,#-1	LOAD.B	D3,#-1	.W	FOS,?SPOS	; positionne  la fin	CALL	SAOPEN		; dessine le sablier	CLR.L	D4	CLR.B	D3	.W	FOS,?SPOS	; positionne au dbut	LOAD.L	A3,#R16"NAPRINT	LOAD.W	D3,#2^BOPWR!2^BOPEXCL ; D3 <-- ouverture en criture	.W	FOS,?OPEN	; ouvre l'imprimante	JUMP,NE	93$	LOAD.W	(A6)+OCHOUT,D6	.W	LIB,?AFTIM	.B	CR,CR	.ASCIZ	"  Pour stopper l'impression, appuyez sur (CTRL-M3)<CR><CR>"	.EVEN	LOAD.W	(A6)+OPRCPA,#1	; rz compteur de pages20$:	LOAD.L	A4,#(A6)+OBUPRI	; A4 <-- ^buffer tampon	LOAD.L	D4,#LBUPRI	; D4 <-- lg buffer tampon	LOAD.W	D6,(A6)+OCHIN	; D6 <-- canal fichier  imprimer	.W	FOS,?RDBYTE	; lit une tranche	LOAD.W	D5,D7		; D5 <-- ok/fini	JUMP,EQ	30$	COMP.W	D7,#EROUTF	JUMP,NE	90$30$:	CALL	SKIPPAGE	; saute si page hors dbut/fin	LOAD.W	D6,(A6)+OCHOUT	; D6 <-- canal imprimante	.W	FOS,?WRBYTE	; crit une tranche	JUMP,NE	90$	CALL	SANEXT		; ok => avance le sablier	TEST.W	D5		; ok/fini ?	JUMP,EQ	20$		; ok => 20$90$:				; fini =>	PUSH.W	D7	LOAD.W	D6,(A6)+OCHOUT	.W	FOS,?CLOSE	; ferme l'imprimante	LOAD.W	D4,#50*3	; D4 <-- trois secondes	.W	NTREL,?DELMS	; attend un peu ...	<<< PROVISOIRE <<<	POP.W	D793$:	PUSH.W	D7	LOAD.W	D6,(A6)+OCHIN	.W	FOS,?CLOSE	; ferme fichier  imprimer	POP.W	D7	CALL	SANEXT		; avance le sablier une dernire fois	CALL	SACLOSE		; ferme la sablier95$:	POPM.L	D3,D4,D5,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\\; SKIPPAGE >;---------/; Saute les pages avant le dbut ou aprs la fin.; in	A4.L	^caractres lus;	D4.L	nombre de caractres; out	A4.L	^dbut;	D4.L	longueur; mod	D4.L, A4.LSKIPPAGE:	PUSHM.L	D2,D3,A0	TEST.L	D4	JUMP,EQ	90$	LOAD.W	D2,(A6)+OPRCPA	; D2 <-- compteur de pages10$:	LOAD.L	A0,A4		; A0 <-- ^dbut	COMP.W	D2,(A6)+OPRBPA	; est-on sur ou aprs le dbut ?	JUMP,HS	40$		; oui => 40$15$:	TEST.L	D4	JUMP,EQ	80$	DEC.L	D4	LOAD.B	D3,(A4+)	COMP.B	D3,#EOP	JUMP,EQ	20$	COMP.B	D3,#EDEOP	JUMP,NE	15$20$:	INC.W	D2		; D2 <-- inc compteur de pages	JUMP	10$40$:	COMP.W	D2,(A6)+OPREPA	; est-on sur ou aprs la fin ?	JUMP,HI	70$		; oui => 70$45$:	TEST.L	D4	JUMP,EQ	70$	DEC.L	D4	LOAD.B	D3,(A4+)	COMP.B	D3,#EOP	JUMP,EQ	50$	COMP.B	D3,#EDEOP	JUMP,NE	45$50$:	INC.W	D2		; D2 <-- inc compteur de pages	JUMP	40$70$:	EX.L	A0,A4		; A4 <-- ^dbut, A0 <-- ^fin	LOAD.L	D4,A0	SUB.L	D4,A4		; D4 <-- longueur80$:	LOAD.W	(A6)+OPRCPA,D2	; mj compteur de pages90$:	POPM.L	D2,D3,A0	RET; Gestion de l'indicateur d'avance; --------------------------------;--------\\; SAOPEN  >;========/; Dessine le sablier.; in	D4.L	longueur du fichier; out	-; mod	D7.WSAOPEN:	PUSHM.L	D3,D4,D6	ADD.L	D4,#LBUPRI	DIV.WU	D4,#LBUPRI	; D4 <-- nb tranches du fichier	LOAD.L	D3,D4	SWAP.W	D3		; D3 <-- reste	TEST.W	D3		; reste qq chose ?	JUMP,EQ	10$		; non => 10$	INC.W	D4		; oui => une tranche (partielle) de plus10$:	.W	SABLIER_OPEN	LOAD.L	(A6)+OSABLIER,D6	POPM.L	D3,D4,D6	RET;--------\\; SANEXT  >;========/; Avance le sablier.; in	-; out	-; mod	-SANEXT:	PUSHM.L	D6,D7	LOAD.L	D6,(A6)+OSABLIER	.W	SABLIER_NEXT	POPM.L	D6,D7	RET;--------\\; SACLOSE >;========/; Ferme le sablier.; in	-; out	-; mod	D7.WSACLOSE:	PUSHM.L	D6,D7	LOAD.L	D6,(A6)+OSABLIER	.W	SABLIER_CLOSE	POPM.L	D6,D7	RET; Gestion des DBOX; ----------------;----------\\; DBOXPRINT >;==========/; Affiche la DBOX juste avant d'imprimer un fichier.; in	-; out	D7.W	erreur; mod	D7.WDBOXPRINT:	PUSHM.L	D0,D1,D2,D3,D4,D5,A2,A3,A4	LOAD.L	A2,#R16"TDBOX_PRINT	LOAD.W	D2,#2^BDBSAV	; D2 <-- mode d'ouverture	CLR.L	D4		; D4 <-- fanions	.W	DBOX_OPEN	; ouvre la DBOX	JUMP,NE	90$	LOAD.W	(A6)+OPRNBC,#1	LOAD.W	(A6)+OPRBPA,#1	LOAD.W	(A6)+OPREPA,#999	CLR.W	D2		; D2 <-- choix nb copies20$:	CLR.W	D0		; D0 <-- rang digit22$:	CALL	DBOXAFN		; affiche un nombre	.W	DBOX_EDIT	; attend une action ...	LOAD.L	A1,#R16"TKEY_PRINT	LOAD.W	D1,#2^BDBCCMM!2^BDBCCFF	.W	DBOX_CALLC	CLR.W	D7		; D7 <-- [OK]	COMP.W	D3,#F1	JUMP,EQ	80$	INC.W	D7		; D7 <-- [ANNULE]	COMP.W	D3,#END	JUMP,EQ	80$	COMP.W	D3,#F7	JUMP,EQ	50$	COMP.W	D3,#F10	JUMP,EQ	52$	COMP.W	D3,#F13	JUMP,EQ	54$	COMP.W	D3,#CR	JUMP,EQ	60$	COMP.W	D3,#DEL	JUMP,EQ	62$	COMP.W	D3,#UNDO	JUMP,EQ	64$	COMP.W	D3,#'0	JUMP,LO	30$	COMP.W	D3,#'9	JUMP,LS	70$30$:	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; p'tit bruit	JUMP	22$50$:				; NB COPIES =>	CLR.W	D2	JUMP	56$52$:				; PREMIERE PAGE =>	LOAD.W	D2,#1	JUMP	56$54$:				; DERNIERE PAGE =>	LOAD.W	D2,#2;	JUMP	56$56$:	PUSH.W	D2	CLR.W	D2	CALL	DBOXAFN		; affiche nb copies	INC.W	D2	CALL	DBOXAFN		; affiche 1re page	INC.W	D2	CALL	DBOXAFN		; affiche 2me page	POP.W	D2	JUMP	20$60$:				; RETURN =>	INC.W	D2	COMP.W	D2,#3	JUMP,LO	56$	CLR.W	D2	JUMP	56$62$:				; DEL =>	TEST.W	D0		; premier digit ?	JUMP,EQ	64$		; oui => 64$	CLR.L	D1	LOAD.W	D1,(A4)	DIV.WU	D1,#10	LOAD.W	(A4),D1	DEC.W	D0		; D0 <-- un digit de moins	JUMP	22$64$:				; UNDO =>	CLR.W	(A4)	JUMP	20$70$:				; DIGIT =>	COMP.W	D0,#3		; trop de digits ?	JUMP,HS	30$		; oui => 30$	CLR.W	D1	TEST.W	D0		; premier digit ?	JUMP,EQ	72$		; oui => 72$	LOAD.W	D1,(A4)72$:	MUL.WU	D1,#10		; pousse d'un digit	SUB.W	D3,#'0		; D3 <-- 0..9	ADD.W	D1,D3		; ajoute nouveau digit	LOAD.W	(A4),D1	INC.W	D0		; D0 <-- un digit de plus	JUMP	22$80$:	PUSH.W	D7	.W	DBOX_CLOSE	; ferme la DBOX	POP.W	D7	LOAD.W	D3,(A6)+OPRBPA	; dbut=0 ?	JUMP,NE	84$		; non => 84$	INC.W	D3		; oui =>	LOAD.W	(A6)+OPRBPA,D3	; met au moins 184$:	COMP.W	D3,(A6)+OPREPA	; fin avant le dbut ?	JUMP,LS	90$		; non => 90$	LOAD.W	(A6)+OPREPA,D3	; oui => met fin=dbut90$:	POPM.L	D0,D1,D2,D3,D4,D5,A2,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; DBOXAFN >;--------/; Affiche un nombre dans la DBOX.; in	D2.W	rang du nombre (0..2); out	A4.L	^nombre (.W); mod	D7.W, A4.LDBOXAFN:	PUSHM.L	D1,D2,D3,D4	LOAD.B	D3,#NOCURS	.W	LIB,?AFCAR	; plus de curseur	LOAD.L	A4,#R16"10$	SL.W	D2,#2		; *4	LOAD.W	D1,(A4)+(D2.W)+0 ; D1 <-- offset variable	LOAD.W	D2,(A4)+(D2.W)+2 ; D2 <-- rang dans DBOX	.W	DBOX_GETCO	; D3 <-- coordonne	.W	LIB,?SETCURS	; positionne	LOAD.L	A4,#(A6)+(D1.W)	; A4 <-- ^nombre	CLR.L	D4	LOAD.W	D4,(A4)		; D4 <-- nombre	LOAD.W	D3,#3		; D3 <-- nb digits (0..999)	CLR.W	D2		; D2 <-- mode	.W	LIB,?AFDEC	; affiche le nombre	LOAD.B	D3,#CURS	.W	LIB,?AFCAR	; remet le curseur	POPM.L	D1,D2,D3,D4	RET10$:	.W	OPRNBC,1	.W	OPRBPA,3	.W	OPREPA,5;--------\\; DBOXMAJ >;========/; Demande confirmation avant de mettre  jour le status; de l'imprimante.; in	-; out	D7.W	oui = zro; mod	D7.WDBOXMAJ:	PUSHM.L	D0,D1,D2,D3,D4,D5,A2,A3,A4	LOAD.L	A2,#R16"TDBOX_MAJ	LOAD.W	D2,#2^BDBSAV	; D2 <-- mode d'ouverture	LOAD.L	D4,#B'01	; D4 <-- fanions	.W	DBOX_OPEN	; ouvre la DBOX	JUMP,NE	90$20$:	.W	DBOX_EDIT	; attend une action ...	LOAD.L	A1,#R16"TKEY_MAJ	LOAD.W	D1,#2^BDBCCMM!2^BDBCCFF	.W	DBOX_CALLC	JUMP,EQ	50$	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; p'tit bruit	JUMP	20$50$:	.W	DBOX_CLOSE	; ferme la DBOX	CLR.W	D7		; D7 <-- oui	COMP.W	D3,#'O	JUMP,EQ	90$	INC.W	D7		; D7 <-- non90$:	POPM.L	D0,D1,D2,D3,D4,D5,A2,A3,A4	TEST.W	D7		; retour EQ/NE	RET	.INS	PRICOMM; Textes; ------LIBLIST:	.W	?GETFILE	.W	?ADDEXT	.W	?SETBARRE	.W	-1NAMDBOX:.ASCIZ	"DBOX"		; nom du module DBOXNAMSABL:.ASCIZ	"SABLIER"	; nom du module SABLIEREXTDEF:	.ASCIZ	".text"		; extension par dfautNAPRINT:.ASCIZ	"#printer"	; nom de l'imprimante	.B	0TAFONTES:	.ASCIZ	"Normal"	.ASCIZ	"Messenger"	.ASCIZ	"Univers"	.ASCIZ	"Times"	.B	0TASTYLES:	.ASCIZ	"Roman"	.ASCIZ	"Bold"	.ASCIZ	"Italique"	.ASCIZ	"Qualit"	.B	0TKMEN0:	.B	F1	.ASCIZ	"#mm0:"	.B	F2	.ASCIZ	"#mm1:"	.B	F3	.ASCIZ	"#mm2:"	.B	F10	.ASCIZ	".text<CR>"	.B	F11	.ASCIZ	".bas<CR>"	.B	F12	.ASCIZ	".asm<CR>"	.B	F13	.ASCIZ	".image<CR>"	.B	0TXMENU:	.ASCIZ	""	.ASCIZ	"Fin"	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""TXMEN0:	.ASCIZ	""	.ASCIZ	"Fin"	.ASCIZ	""	.ASCIZ	"#mm0: #mm1: #mm2:";		!     !     !     !	.ASCIZ	""	.ASCIZ	"";		!     !     !     !	.ASCIZ	""	.ASCIZ	"";		!     !     !     !	.ASCIZ	""	.ASCIZ	".text .bas  .asm ";		!     !     !     !	.ASCIZ	""	.ASCIZ	".image           "TXMEN1:	.ASCIZ	""	.ASCIZ	"Fin"	.ASCIZ	""	.ASCIZ	"Descend";		!     !     !     !	.ASCIZ	""	.ASCIZ	"Monte";		!     !     !     !	.ASCIZ	""	.ASCIZ	"";		!     !     !     !	.ASCIZ	""	.ASCIZ	"Diminue"	.ASCIZ	""	.ASCIZ	"Augmente"	.EVENTDBOX_PRINT:	.W	10$-TDBOX_PRINT	.W	20$-TDBOX_PRINT	.W	0,010$:	.B	ODBTEXT	.ASCIZ	"Nombre de copies "	.B	ODBBOX,0,F7,TDBNORM	.ASCIZ	"    "	.B	ODBCR,ODBCR	.B	ODBTEXT	.ASCIZ	"Pages "	.B	ODBBOX,0,F10,TDBNORM	.ASCIZ	"    "	.B	ODBTEXT	.ASCIZ	"  "	.B	ODBBOX,0,F13,TDBNORM	.ASCIZ	"    "	.B	ODBCR,ODBCR,ODBCR,ODBCR	.B	ODBBOX,0,F1,TDBMEV	.ASCIZ	"   OK   "	.B	ODBTEXT	.ASCIZ	"    "	.B	ODBBOX,0,END,TDBNORM	.ASCIZ	" ANNULE "	.B	0	.EVEN20$:	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	"OK"	.ASCIZ	""	.ASCIZ	"Annule"	.ASCIZ	""	.ASCIZ	"Nombre de copies"	.ASCIZ	""	.ASCIZ	"Premire page"	.ASCIZ	""	.ASCIZ	"Dernire page"	.EVENTKEY_PRINT:	.W	END,F0,F4,F5,F6,0	10$-TKEY_PRINT	.W	F1,F2,F3,0		20$-TKEY_PRINT	.W	F7,F8,F9,0		30$-TKEY_PRINT	.W	F10,F11,F12,0		40$-TKEY_PRINT	.W	F13,F14,F15,0		50$-TKEY_PRINT	.W	DEL,BS,DELETE,0		60$-TKEY_PRINT	.W	UNDO,CLEAR,0		70$-TKEY_PRINT	.W	CR,ENTER,0		80$-TKEY_PRINT	.W	010$:	LOAD.W	D3,#END	RET20$:	LOAD.W	D3,#F1	RET30$:	LOAD.W	D3,#F7	RET40$:	LOAD.W	D3,#F10	RET50$:	LOAD.W	D3,#F13	RET60$:	LOAD.W	D3,#DEL	RET70$:	LOAD.W	D3,#UNDO	RET80$:	LOAD.W	D3,#CR	RETTDBOX_MAJ:	.W	10$-TDBOX_MAJ	.W	20$-TDBOX_MAJ	.W	0,010$:	.B	ODBTEXT	.ASCIZ	"Mise  jour de l'imprimante ?"	.B	ODBCR,ODBCR,ODBCR	.B	ODBBOX,0,'O,TDBMEV	.ASCIZ	"  OUI  "	.B	ODBTEXT	.ASCIZ	"     "	.B	ODBBOX,0,'N,TDBNORM	.ASCIZ	"  NON  "	.B	0	.EVEN20$:	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	"Oui"	.ASCIZ	""	.ASCIZ	"Non"	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.ASCIZ	""	.EVENTKEY_MAJ:	.W	'O,'Y,'J,'S,F1,F2,F3,0	10$-TKEY_MAJ	.W	'N,F4,F5,F6,0		20$-TKEY_MAJ	.W	010$:	LOAD.W	D3,#'O	RET20$:	LOAD.W	D3,#'N	RET	.END	START